import React, { useState } from 'react';
import { useApp } from '../../context/AppContext';
import { Eye, EyeOff, Mail, Lock, User } from 'lucide-react';
import './Auth.css';

const demoCredentials = {
  admin: { email: 'admin@dulceria.com', password: '123456' },
  cliente: { email: 'maria@dulceria.com', password: '123456' },
  vendor: { email: 'laura@dulceria.com', password: '123456' },
};

export default function AuthPage() {
  const { login, register } = useApp();
  const [mode, setMode] = useState('login');
  const [form, setForm] = useState({ name: '', email: '', password: '' });
  const [showPass, setShowPass] = useState(false);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  const handle = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const resetMessages = () => {
    setError('');
    setSuccessMsg('');
  };

  const submit = (e) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');

    if (mode === 'login') {
      const res = login(form.email, form.password);
      if (res.error) setError(res.error);
      return;
    }

    if (mode === 'register') {
      if (!form.name.trim()) {
        setError('El nombre es requerido.');
        return;
      }

      const res = register(form.name, form.email, form.password);
      if (res.error) setError(res.error);
      return;
    }

    setSuccessMsg('Si el correo existe, recibirás instrucciones para restablecer tu contraseña.');
  };

  const demo = (accountRole) => {
    const credentials = demoCredentials[accountRole];
    login(credentials.email, credentials.password);
  };

  if (mode === 'forgot') {
    return (
      <div className="min-h-screen bg-background flex flex-col">
        <main className="flex-1 flex items-center justify-center px-4 py-8">
          <div className="w-full max-w-[700px] bg-surface-container-lowest rounded-2xl shadow-[0_24px_70px_rgba(64,34,16,0.12)] overflow-hidden">
            <div className="p-8 md:p-10">
              <div className="flex items-center gap-3 mb-6">
                <div className="w-14 h-14 rounded-2xl bg-tertiary-container flex items-center justify-center text-tertiary">
                  <Lock size={28} />
                </div>
                <div>
                  <h1 className="font-headline-lg text-headline-lg text-primary">Recuperar contraseña</h1>
                  <p className="font-body-md text-body-md text-secondary">Ingresa tu correo y te enviaremos instrucciones para restablecer tu contraseña.</p>
                </div>
              </div>

              {error && <div className="mb-4 rounded-lg border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">{error}</div>}
              {successMsg && <div className="mb-4 rounded-lg border border-green-200 bg-green-50 px-4 py-3 text-sm text-green-700">{successMsg}</div>}

              <form onSubmit={submit} className="space-y-4">
                <div className="space-y-2">
                  <label className="font-label-md text-label-md text-on-secondary-fixed-variant" htmlFor="forgot-email">Correo electrónico</label>
                  <div className="relative group">
                    <span className="material-symbols-outlined absolute left-4 top-1/2 -translate-y-1/2 text-outline group-focus-within:text-primary transition-colors">mail</span>
                    <input
                      id="forgot-email"
                      name="email"
                      type="email"
                      placeholder="correo@ejemplo.com"
                      value={form.email}
                      onChange={handle}
                      required
                      className="w-full pl-12 pr-4 py-4 bg-secondary-container/30 border-b-2 border-secondary focus:border-primary focus:ring-0 transition-all outline-none font-body-md text-on-surface placeholder:text-outline/50"
                    />
                  </div>
                </div>

                <button type="submit" className="w-full py-4 bg-primary text-on-primary font-label-md text-label-md rounded-lg soft-glow hover:bg-on-primary-fixed-variant transition-all active:scale-[0.98] duration-150">
                  Enviar instrucciones
                </button>

                <div className="text-center pt-2">
                  <button type="button" className="font-label-md text-label-md text-primary hover:underline" onClick={() => { setMode('login'); resetMessages(); }}>
                    Volver a inicio
                  </button>
                </div>
              </form>
            </div>
          </div>
        </main>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background flex flex-col overflow-x-hidden">
      <main className="flex-1 flex items-center justify-center px-4 py-8 relative">
        <div className="absolute inset-0 opacity-20 pointer-events-none overflow-hidden">
          <div className="absolute top-10 left-10 w-32 h-32 rounded-full bg-primary-container blur-3xl opacity-30"></div>
          <div className="absolute bottom-20 right-10 w-48 h-48 rounded-full bg-tertiary-container blur-3xl opacity-20"></div>
          <div className="absolute top-1/2 left-1/4 w-24 h-24 rounded-full bg-secondary-container blur-2xl opacity-40"></div>
        </div>

        <div className="w-full max-w-[1100px] grid md:grid-cols-2 bg-surface-container-lowest rounded-2xl overflow-hidden relative z-10 shadow-[0_10px_40px_-10px_rgba(53,102,104,0.15)]">
          <div className="hidden md:block relative min-h-[600px]">
            <img
              className="w-full h-full object-cover"
              src={process.env.PUBLIC_URL + '/img/dulces/canasto.png'}
              alt="Canasto de dulces"
            />
            <div className="absolute inset-0 bg-primary/10 mix-blend-overlay"></div>
            <div className="absolute bottom-12 left-12 right-12 text-white">
              <h2 className="font-headline-lg text-headline-lg mb-3 leading-tight">Artisan Sweets, Crafted with Love.</h2>
              <p className="font-body-md text-body-md text-white/90">Experience the magic of traditional confectionery reinvented for modern palates.</p>
            </div>
          </div>

          <div className="p-8 md:p-16 flex flex-col justify-center">
            <div className="mb-10 text-center md:text-left">
              <h1 className="font-headline-lg text-headline-lg text-primary tracking-tight mb-2">Dulcería El Suspiro</h1>
              <p className="font-body-md text-body-md text-secondary">
                {mode === 'login'
                  ? 'Bienvenido de vuelta, ingresa tus datos.'
                  : mode === 'register'
                    ? 'Crea tu cuenta para continuar.'
                    : 'Restablece tu contraseña.'}
              </p>
            </div>

            {error && <div className="mb-4 rounded-lg border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">{error}</div>}
            {successMsg && <div className="mb-4 rounded-lg border border-green-200 bg-green-50 px-4 py-3 text-sm text-green-700">{successMsg}</div>}

            <div className="flex gap-3 mb-6 p-1 rounded-xl bg-secondary-container/40">
              <button
                type="button"
                className={mode === 'login' ? 'flex-1 py-3 rounded-lg bg-primary text-white font-label-md text-label-md soft-glow' : 'flex-1 py-3 rounded-lg text-secondary font-label-md text-label-md'}
                onClick={() => { setMode('login'); resetMessages(); }}
              >
                Ingreso
              </button>
              <button
                type="button"
                className={mode === 'register' ? 'flex-1 py-3 rounded-lg bg-primary text-white font-label-md text-label-md soft-glow' : 'flex-1 py-3 rounded-lg text-secondary font-label-md text-label-md'}
                onClick={() => { setMode('register'); resetMessages(); }}
              >
                Registro
              </button>
            </div>

            <form onSubmit={submit} className="space-y-5">
              {mode === 'register' && (
                <div className="space-y-2">
                  <label className="font-label-md text-label-md text-on-secondary-fixed-variant" htmlFor="name">Nombre completo</label>
                  <div className="relative group">
                    <span className="material-symbols-outlined absolute left-4 top-1/2 -translate-y-1/2 text-outline group-focus-within:text-primary transition-colors">person</span>
                    <input
                      id="name"
                      name="name"
                      type="text"
                      placeholder="Tu nombre"
                      value={form.name}
                      onChange={handle}
                      required
                      className="w-full pl-12 pr-4 py-4 bg-secondary-container/30 border-b-2 border-secondary focus:border-primary focus:ring-0 transition-all outline-none font-body-md text-on-surface placeholder:text-outline/50"
                    />
                  </div>
                </div>
              )}

              <div className="space-y-2">
                <label className="font-label-md text-label-md text-on-secondary-fixed-variant" htmlFor="email">Correo electrónico</label>
                <div className="relative group">
                  <span className="material-symbols-outlined absolute left-4 top-1/2 -translate-y-1/2 text-outline group-focus-within:text-primary transition-colors">mail</span>
                  <input
                    id="email"
                    name="email"
                    type="email"
                    placeholder="hello@example.com"
                    value={form.email}
                    onChange={handle}
                    required
                    className="w-full pl-12 pr-4 py-4 bg-secondary-container/30 border-b-2 border-secondary focus:border-primary focus:ring-0 transition-all outline-none font-body-md text-on-surface placeholder:text-outline/50"
                  />
                </div>
              </div>

              <div className="space-y-2">
                <div className="flex justify-between items-center gap-4">
                  <label className="font-label-md text-label-md text-on-secondary-fixed-variant" htmlFor="password">Contraseña</label>
                  {mode === 'login' && (
                    <button
                      type="button"
                      className="font-label-md text-label-md text-primary hover:underline transition-all"
                      onClick={() => { setMode('forgot'); resetMessages(); }}
                    >
                      ¿Olvidaste tu contraseña?
                    </button>
                  )}
                </div>
                <div className="relative group">
                  <span className="material-symbols-outlined absolute left-4 top-1/2 -translate-y-1/2 text-outline group-focus-within:text-primary transition-colors">lock</span>
                  <input
                    id="password"
                    name="password"
                    type={showPass ? 'text' : 'password'}
                    placeholder="••••••••"
                    value={form.password}
                    onChange={handle}
                    required
                    className="w-full pl-12 pr-12 py-4 bg-secondary-container/30 border-b-2 border-secondary focus:border-primary focus:ring-0 transition-all outline-none font-body-md text-on-surface placeholder:text-outline/50"
                  />
                  <button
                    type="button"
                    className="absolute right-4 top-1/2 -translate-y-1/2 text-outline hover:text-primary transition-colors"
                    onClick={() => setShowPass(!showPass)}
                    aria-label={showPass ? 'Ocultar contraseña' : 'Mostrar contraseña'}
                  >
                    {showPass ? <EyeOff size={18} /> : <Eye size={18} />}
                  </button>
                </div>
              </div>

              <div className="flex items-center gap-3 py-2">
                <input id="remember" type="checkbox" className="w-5 h-5 rounded border-secondary text-primary focus:ring-primary/20" />
                <label htmlFor="remember" className="font-label-md text-label-md text-secondary">Mantener sesión iniciada por 30 días</label>
              </div>

              <button type="submit" className="w-full py-4 bg-primary text-on-primary font-label-md text-label-md rounded-lg soft-glow hover:bg-on-primary-fixed-variant transition-all active:scale-[0.98] duration-150">
                {mode === 'login' ? 'Iniciar sesión' : 'Crear cuenta'}
              </button>
            </form>

            {mode === 'login' && (
              <>
                <div className="mt-12">
                  <div className="relative flex items-center mb-10">
                    <div className="flex-grow border-t border-outline-variant"></div>
                    <span className="flex-shrink mx-4 font-label-md text-label-md text-outline">o continuar con</span>
                    <div className="flex-grow border-t border-outline-variant"></div>
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <button type="button" onClick={() => demo('admin')} className="flex items-center justify-center gap-2 py-3 border border-outline-variant rounded-lg font-label-md text-label-md text-on-surface-variant hover:bg-surface-container transition-all active:scale-[0.98]">
                      Google
                    </button>
                    <button type="button" onClick={() => demo('cliente')} className="flex items-center justify-center gap-2 py-3 border border-outline-variant rounded-lg font-label-md text-label-md text-on-surface-variant hover:bg-surface-container transition-all active:scale-[0.98]">
                      Apple
                    </button>
                  </div>
                </div>

                <p className="mt-12 text-center font-body-md text-body-md text-secondary">
                  New to El Suspiro?{' '}
                  <button type="button" className="text-primary font-bold hover:underline" onClick={() => { setMode('register'); resetMessages(); }}>
                    Create an account
                  </button>
                </p>
              </>
            )}

            {mode === 'register' && (
              <p className="mt-12 text-center font-body-md text-body-md text-secondary">
                ¿Ya tienes cuenta?{' '}
                <button type="button" className="text-primary font-bold hover:underline" onClick={() => { setMode('login'); resetMessages(); }}>
                  Inicia sesión
                </button>
              </p>
            )}
          </div>
        </div>
      </main>
    </div>
  );
}
